xpath.script:
(function () {
    var params = new URLSearchParams(window.location.search);
    var salaryId = params.get('salary_level_id');
    var stateId = params.get('state_id');

    function injectParams() {
        var topbar = document.querySelector('.o_wevent_index_topbar_filters');
        if (!topbar) return;

        var dropdownMenus = topbar.querySelectorAll('.dropdown .dropdown-menu');
        dropdownMenus.forEach(function(menu) {
            var links = menu.querySelectorAll('a.dropdown-item');
            if (!links.length) return;

            // Kiểm tra xem menu này đang xử lý filter nào
            var isSalaryMenu = false;
              var isStateMenu = false;
            if (links.length > 1) {
                var secondHref = links[1].getAttribute('href') || '';
                if (secondHref.includes('salary_level_id=')) {
                    isSalaryMenu = true;
                }
              if (secondHref.includes('state_id=')) {
                    isStateMenu = true;
                }
            }

            links.forEach(function(link) {
                try {
                    var href = link.getAttribute('href');
                    if (!href) return;
                    var url = new URL(href, window.location.origin);

                    // Inject salary_level_id vào các filter KHÔNG phải salary
                    if (salaryId && !isSalaryMenu) {
                        url.searchParams.set('salary_level_id', salaryId);
                    }

                       // Inject state_id vào các filter KHÔNG phải state
                    if (stateId && !isStateMenu) {
                        url.searchParams.set('state_id', stateId);
                    }

                    link.setAttribute('href', url.toString());
                } catch(e) {}
            });
        });
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', injectParams);
    } else {
        injectParams();
    }
})();
